wait until((#SmokeDetector).smokeDetector_smoke == true)
    phase = 1
    (#Siren).siren_setSirenMode("emergency")
    delay(5 SEC)
(#Siren #Switch).switch_off()
}
else {
(#Siren).siren_setSirenMode("emergency")
    delay(5 SEC)
(#Siren #Switch).switch_off()
}

